import './App.css';
import 'bootstrap/dist/css/bootstrap.min.css'; // Import Bootstrap CSS
import { BrowserRouter as Router, Route, Routes} from "react-router-dom";
import Navbar from './Components/NavBar.js';
import Home from './Components/Home.js';
import Analog from './Components/Analog.js';
import Creepypasta from './Components/Creepypasta.js';
import React, {Component} from "react";


class App extends Component {
  render() {


    return (
      <div className="App .bg-secondary.bg-gradient container-fluid d-flex  justify-content-center">
      <Router>
        <div>
        <Navbar/>
        <Routes>
          <Route path="/"  element={<Home/>} />
          <Route path="/analog"  element={<Analog/>} />
          <Route path="/creepypasta" element={<Creepypasta/>} />
        </Routes>
        </div>
      </Router>
      </div>

    );
  }
}

export default App;


